// Mueve un cliente entre columnas del Kanban de Customer Success.
// Payload esperado:
//   { ficha_id, cs_estado, movido_por?, notas? }
//
// cs_estado puede ser uno de los slugs válidos o null para 'sin clasificar'.
// Validamos antes de patchear para evitar que el CHECK de Postgres devuelva
// un mensaje opaco.
const raw  = $input.first().json || {};
const body = (raw.body && typeof raw.body === 'object') ? raw.body : raw;
const now  = new Date().toISOString();
const errores = [];

const ESTADOS_VALIDOS = [
  'en_implementacion',
  'post_primer_mes',
  'reunion_post_1_mes_agendada',
  'posible_escalado',
  'stand_by',
  'critico',
  'sanacion',
  'post_3_meses'
];

const fichaId = body.ficha_id;
if (!fichaId) errores.push('ficha_id obligatorio');
else if (!/^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i.test(fichaId))
  errores.push('ficha_id no es UUID válido');

// cs_estado: aceptamos null/undefined/'' como 'sin clasificar' (NULL en BD).
let csEstado = body.cs_estado;
if (csEstado === undefined || csEstado === '' || csEstado === null) {
  csEstado = null;
} else if (!ESTADOS_VALIDOS.includes(csEstado)) {
  errores.push('cs_estado inválido: ' + csEstado);
}

if (errores.length > 0) {
  return [{ json: { __error: true, __errores: errores } }];
}

return [{ json: {
  ficha_id: fichaId,
  cs_estado: csEstado,
  movido_por: body.movido_por != null ? String(body.movido_por) : null,
  notas:      body.notas      != null ? String(body.notas)      : null,
  __qs_ficha: 'id=eq.' + encodeURIComponent(fichaId),
  __ts: now
} }];

