// Normaliza la salida al shape único del frontend:
//   { success, ficha_id, cs_estado, errores }
const prep = $('Validar payload').first().json || {};
if (prep.__error) {
  return [{ json: { success: false, ficha_id: null, cs_estado: null, errores: prep.__errores || ['validación falló'] } }];
}

function _msgError(j) {
  if (!j) return null;
  if (j.error) {
    if (typeof j.error === 'string') return j.error;
    const m = j.error.message || j.error.detail || j.error.details || j.error.hint;
    if (m) return j.error.code ? (m + ' [' + j.error.code + ']') : m;
  }
  if (j.code && j.message && !j.id) {
    return j.message + (j.details ? ' (' + j.details + ')' : '') + ' [' + j.code + ']';
  }
  return null;
}

const errores = [];
let fila = null;

// PATCH fichas_alta
try {
  const items = $('PATCH fichas_alta cs_estado').all() || [];
  for (const it of items) {
    const j = (it && it.json) ? it.json : it;
    const m = _msgError(j);
    if (m) { errores.push('PATCH ficha: ' + m); continue; }
    if (Array.isArray(j) && j.length > 0) fila = j[0];
    else if (j && j.id) fila = j;
  }
  if (!fila && errores.length === 0) {
    errores.push('PATCH ficha: no se actualizó ninguna fila (¿id correcto?)');
  }
} catch (e) { errores.push('PATCH ficha: ' + (e.message || e)); }

// INSERT historial — fallo aquí no bloquea, pero lo apuntamos.
try {
  const items = $('INSERT historial').all() || [];
  for (const it of items) {
    const j = (it && it.json) ? it.json : it;
    const m = _msgError(j);
    if (m) errores.push('historial: ' + m);
  }
} catch (_) {}

return [{ json: {
  success: !!fila && errores.filter(e => e.startsWith('PATCH')).length === 0,
  ficha_id: prep.ficha_id,
  cs_estado: fila ? fila.cs_estado : prep.cs_estado,
  errores
} }];
